<?php
namespace App\Services;
use App\Models\Campaign; use Illuminate\Http\UploadedFile; use Illuminate\Support\Facades\DB; use Illuminate\Support\Str;
class CampaignService { public function store(array $data, int $fundraiserId): Campaign { return DB::transaction(function() use($data,$fundraiserId){ $data['fundraiser_id']=$fundraiserId; $data['slug']=Str::slug($data['title']).'-'.Str::lower(Str::random(6)); $data['status']=$data['status'] ?? 'pending'; if (($data['thumbnail'] ?? null) instanceof UploadedFile) $data['thumbnail_path']=$data['thumbnail']->store('campaigns','public'); if (($data['supporting_document'] ?? null) instanceof UploadedFile) $data['supporting_document_path']=$data['supporting_document']->store('verification-documents','public'); unset($data['thumbnail'],$data['supporting_document']); return Campaign::create($data); }); } public function update(Campaign $campaign, array $data): Campaign { return DB::transaction(function() use($campaign,$data){ if (($data['thumbnail'] ?? null) instanceof UploadedFile) $data['thumbnail_path']=$data['thumbnail']->store('campaigns','public'); if (($data['supporting_document'] ?? null) instanceof UploadedFile) $data['supporting_document_path']=$data['supporting_document']->store('verification-documents','public'); unset($data['thumbnail'],$data['supporting_document']); $campaign->update($data); return $campaign; }); } public function verify(Campaign $campaign, array $data, int $adminId, ?string $ip, ?string $ua): Campaign { return DB::transaction(function() use($campaign,$data,$adminId,$ip,$ua){ $approved=$data['action']==='approve'; $campaign->update(['status'=>$approved?'active':'rejected','admin_notes'=>$data['admin_notes'] ?? null,'verified_by'=>$adminId,'verified_at'=>now()]); $campaign->verificationLogs()->create(['admin_id'=>$adminId,'action'=>$approved?'approved':'rejected','notes'=>$data['admin_notes'] ?? null,'ip_address'=>$ip,'user_agent'=>$ua]); return $campaign; }); } }
